        [Test]
        public void ParseTerminalPhone_ReturnTrue()
        {
            var city = JsonConvert.DeserializeObject<RawCityDTO>(CityString);

            Assert.That(city?.TerminalList?.Terminals.Count, Is.EqualTo(1));

            var terminal = city.TerminalList.Terminals.First();


            Assert.That(terminal?.Phones?.Count, Is.EqualTo(1));

            Assert.That(terminal?.Phones?.First().IsPrimary, Is.True);

            Assert.That(terminal?.Phones?.First().Number, Is.EqualTo(terminal ?.MainPhone));
        }
